import React, { useRef, useState } from "react";

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  importType: string | null;
  setImportType: (type: any) => void;
  selectedFiles: File[];
   setSelectedFiles: React.Dispatch<React.SetStateAction<File[]>>; // ✅ Type correct
  uploadProgress: number;
  setUploadProgress: React.Dispatch<React.SetStateAction<number>>;
  isUploading: boolean;
  setIsUploading: (uploading: boolean) => void;
  onUpload: (file: File, metadata?: Record<string, any>) => Promise<any>;
}

// ✅ STATUT D'UPLOAD PAR FICHIER
interface FileUploadStatus {
  id: string;
  file: File;
  progress: number;
  status: 'pending' | 'uploading' | 'success' | 'error';
  error?: string;
  result?: any;
}

const ImportModal: React.FC<ImportModalProps> = ({
  isOpen,
  onClose,
  importType,
  setImportType,
  selectedFiles,
  setSelectedFiles,
  uploadProgress,
  setUploadProgress,
  isUploading,
  setIsUploading,
  onUpload,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  // ✅ SUIVI INDIVIDUEL PAR FICHIER
  const [fileStatuses, setFileStatuses] = useState<FileUploadStatus[]>([]);
  const [fileIds, setFileIds] = useState<string[]>([]); // ✅ NOUVEL ÉTAT


  const importOptions = [
    {
      id: 'raw',
      title: 'Fichier Brut',
      icon: 'fa-file-import',
      color: 'from-blue-500 to-blue-600',
      description: 'PDF, Audio, Image',
      accepted: '.pdf,.mp3,.wav,.mp4,.jpg,.jpeg,.png'
    },
    {
      id: 'transcription',
      title: 'Transcription',
      icon: 'fa-keyboard',
      color: 'from-green-500 to-green-600',
      description: 'Texte transcrit',
      accepted: '.txt,.doc,.docx'
    },
    {
      id: 'book',
      title: 'Projet de Livre',
      icon: 'fa-book',
      color: 'from-purple-500 to-purple-600',
      description: 'Assemblage de transcriptions',
      accepted: '.txt,.doc,.docx,.pdf'
    },
    {
      id: 'proofreading1',
      title: 'Relecture 1',
      icon: 'fa-eye',
      color: 'from-amber-500 to-amber-600',
      description: 'Première relecture',
      accepted: '.txt,.doc,.docx,.pdf'
    },
    {
      id: 'proofreading2',
      title: 'Relecture 2',
      icon: 'fa-eye-double',
      color: 'from-red-500 to-red-600',
      description: 'Seconde relecture',
      accepted: '.txt,.doc,.docx,.pdf'
    },
  ];

  // ✅ Dans handleFileSelect (ligne ~85)
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files);
      setSelectedFiles(filesArray);

      const ids = filesArray.map(() => `${Date.now()}_${Math.random().toString(36).substring(7)}`);
      setFileIds(ids);

      setFileStatuses(
        filesArray.map((file, index) => ({
          id: ids[index],
          file,
          progress: 0,
          status: 'pending' as const,
        }))
      );
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files) {
      setSelectedFiles(Array.from(e.dataTransfer.files));
      setFileStatuses(
        Array.from(e.dataTransfer.files).map(file => ({
          id: `${Date.now()}_${Math.random().toString(36).substring(7)}`,
          file,
          progress: 0,
          status: 'pending' as const,
        }))
      );
    }
  };

  // ✅ VALIDATION DES FICHIERS
  const validateFile = (file: File): { valid: boolean; error?: string } => {
    if (file.size > 50 * 1024 * 1024) {
      return { valid: false, error: 'Fichier trop volumineux (max 50MB)' };
    }

    const allowedTypes = [
      'application/pdf',
      'audio/mpeg',
      'audio/wav',
      'audio/mp4',
      'image/jpeg',
      'image/png',
      'image/gif',
    ];

    if (!allowedTypes.includes(file.type)) {
      return {
        valid: false,
        error: `Type non autorisé (${file.type})`
      };
    }

    return { valid: true };
  };

  // ✅ UPLOAD AVEC PROGRESSION INDIVIDUELLE
  const handleUpload = async () => {
    if (selectedFiles.length === 0 || !importType) {
      alert('⚠️ Veuillez sélectionner des fichiers et un type');
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    // ✅ Initialiser tous les fichiers en "pending"
    const initialStatuses = selectedFiles.map(file => ({
      id: `${Date.now()}_${Math.random().toString(36).substring(7)}`,
      file,
      progress: 0,
      status: 'pending' as const,
    }));
    setFileStatuses(initialStatuses);

    let successCount = 0;
    let errorCount = 0;

    // ✅ Upload fichier par fichier avec progression individuelle
    for (let index = 0; index < selectedFiles.length; index++) {
      const file = selectedFiles[index];
      const fileId = initialStatuses[index].id;

      // ✅ Marquer comme "en cours d'upload"
      setFileStatuses(prev => prev.map(f =>
        f.id === fileId ? { ...f, status: 'uploading' } : f
      ));

      try {
        // ✅ Validation
        const validation = validateFile(file);
        if (!validation.valid) {
          throw new Error(validation.error);
        }

        const metadata = {
          import_type: importType,
          imported_via: 'media_library',
          original_name: file.name,
        };

        // ✅ Simulation de progression (car Supabase ne donne pas de progression réelle)
        const simulateProgress = async () => {
          for (let p = 0; p <= 90; p += 10) {
            await new Promise(resolve => setTimeout(resolve, 100));
            setFileStatuses(prev => prev.map(f =>
              f.id === fileId ? { ...f, progress: p } : f
            ));
            // ✅ Progression globale
            const globalProgress = ((index + (p / 100)) / selectedFiles.length) * 100;
            setUploadProgress(globalProgress);
          }
        };

        // ✅ Lancer la simulation + upload en parallèle
        const progressPromise = simulateProgress();
        const result = await onUpload(file, metadata);
        await progressPromise;

        if (result) {
          successCount++;
          // ✅ Marquer comme "succès"
          setFileStatuses(prev => prev.map(f =>
            f.id === fileId ? { ...f, progress: 100, status: 'success', result } : f
          ));
        } else {
          errorCount++;
          setFileStatuses(prev => prev.map(f =>
            f.id === fileId ? { ...f, status: 'error', error: 'Échec de l\'upload' } : f
          ));
        }

      } catch (err: any) {
        errorCount++;
        console.error('Erreur upload:', err);
        setFileStatuses(prev => prev.map(f =>
          f.id === fileId ? { ...f, status: 'error', error: err.message } : f
        ));
      }

      // ✅ Progression globale mise à jour
      const globalProgress = ((index + 1) / selectedFiles.length) * 100;
      setUploadProgress(globalProgress);
    }

    setIsUploading(false);

    // ✅ Résumé final
    if (successCount > 0) {
      alert(`✅ ${successCount}/${selectedFiles.length} fichier(s) importé(s) avec succès !`);
      onClose();
    } else {
      alert(`❌ Échec de l'import (${errorCount} erreurs)`);
    }
  };

  const currentOption = importOptions.find((opt: any) => opt.id === importType);

  // ✅ Calculer les statistiques d'upload
  const uploadingCount = fileStatuses.filter(f => f.status === 'uploading').length;
  const successCount = fileStatuses.filter(f => f.status === 'success').length;
  const errorCount = fileStatuses.filter(f => f.status === 'error').length;
  const pendingCount = fileStatuses.filter(f => f.status === 'pending').length;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      {/* Overlay */}
      <div
        className="absolute inset-0 bg-black bg-opacity-50 backdrop-blur-sm animate-fade-in"
        onClick={onClose}
      ></div>

      {/* Modale */}
      <div className="relative bg-white dark:bg-gray-800 rounded-2xl shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-y-auto animate-scale-in">
        {/* En-tête */}
        <div className="sticky top-0 bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-4 rounded-t-2xl flex justify-between items-center">
          <h2 className="text-2xl font-bold flex items-center gap-3">
            <i className="fas fa-upload"></i>
            Importer des Fichiers
          </h2>
          <button
            onClick={onClose}
            disabled={isUploading}
            className="p-2 hover:bg-white/20 rounded-lg transition-colors disabled:opacity-50"
          >
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6">
          {/* Étape 1 : Choisir le type */}
          <div className="mb-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
              <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">1</span>
              Choisissez le type de fichier
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {importOptions.map((option) => (
                <button
                  key={option.id}
                  onClick={() => {
                    setImportType(option.id);
                    setSelectedFiles([]);
                    setFileStatuses([]);
                  }}
                  disabled={isUploading}
                  className={`p-4 rounded-xl border-2 transition-all duration-200 text-left disabled:opacity-50 ${importType === option.id
                    ? `border-${option.color.split('-')[1]}-500 bg-${option.color.split('-')[1]}-50 dark:bg-${option.color.split('-')[1]}-900/20`
                    : 'border-gray-200 dark:border-gray-700 hover:border-purple-300 dark:hover:border-purple-500'
                    }`}
                >
                  <div className={`w-12 h-12 bg-gradient-to-br ${option.color} rounded-xl flex items-center justify-center mb-3`}>
                    <i className={`fas ${option.icon} text-white text-xl`}></i>
                  </div>
                  <h4 className="font-semibold text-gray-900 dark:text-white">{option.title}</h4>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{option.description}</p>
                </button>
              ))}
            </div>
          </div>

          {/* Étape 2 : Sélectionner les fichiers */}
          {importType && currentOption && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">2</span>
                Sélectionnez vos fichiers
              </h3>

              {/* Zone de drop */}
              {!isUploading && (
                <div
                  onDrop={handleDrop}
                  onDragOver={(e) => e.preventDefault()}
                  onClick={() => fileInputRef.current?.click()}
                  className="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl p-8 text-center cursor-pointer hover:border-purple-500 dark:hover:border-purple-400 transition-colors bg-gray-50 dark:bg-gray-700/50"
                >
                  <input
                    ref={fileInputRef}
                    type="file"
                    multiple
                    accept={currentOption.accepted}
                    onChange={handleFileSelect}
                    className="hidden"
                  />
                  <i className="fas fa-cloud-upload-alt text-5xl text-gray-400 mb-4"></i>
                  <p className="text-lg font-medium text-gray-700 dark:text-gray-300 mb-2">
                    Glissez-déposez vos fichiers ici
                  </p>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
                    ou cliquez pour parcourir
                  </p>
                  <p className="text-xs text-gray-400 dark:text-gray-500">
                    Formats acceptés : {currentOption.accepted}
                  </p>
                </div>
              )}

              {/* ✅ LISTE DES FICHIERS AVEC PROGRESSION INDIVIDUELLE */}
              {fileStatuses.length > 0 && (
                <div className="mt-4 space-y-3">
                  <div className="flex items-center justify-between mb-2">
                    <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                      {fileStatuses.length} fichier(s) sélectionné(s)
                    </p>
                    <div className="flex gap-2 text-xs">
                      <span className="flex items-center gap-1 text-gray-500">
                        <span className="w-2 h-2 bg-gray-400 rounded-full"></span>
                        En attente ({pendingCount})
                      </span>
                      <span className="flex items-center gap-1 text-blue-500">
                        <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></span>
                        Upload ({uploadingCount})
                      </span>
                      <span className="flex items-center gap-1 text-green-500">
                        <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                        Succès ({successCount})
                      </span>
                      <span className="flex items-center gap-1 text-red-500">
                        <span className="w-2 h-2 bg-red-500 rounded-full"></span>
                        Erreur ({errorCount})
                      </span>
                    </div>
                  </div>

                  {fileStatuses.map((fileStatus) => (
                    <div
                      key={fileStatus.id}
                      className="flex items-center gap-4 bg-gray-50 dark:bg-gray-700 rounded-lg p-4 transition-all duration-200"
                    >
                      {/* Icône de statut */}
                      <div className="flex-shrink-0">
                        {fileStatus.status === 'pending' && (
                          <i className="fas fa-file text-gray-400 text-xl"></i>
                        )}
                        {fileStatus.status === 'uploading' && (
                          <i className="fas fa-spinner fa-spin text-blue-500 text-xl"></i>
                        )}
                        {fileStatus.status === 'success' && (
                          <i className="fas fa-check-circle text-green-500 text-xl"></i>
                        )}
                        {fileStatus.status === 'error' && (
                          <i className="fas fa-times-circle text-red-500 text-xl"></i>
                        )}
                      </div>

                      {/* Infos fichier */}
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-gray-900 dark:text-white truncate">
                          {fileStatus.file.name}
                        </p>
                        <p className="text-xs text-gray-500 dark:text-gray-400">
                          {(fileStatus.file.size / 1024 / 1024).toFixed(2)} MB
                        </p>

                        {/* ✅ BARRE DE PROGRESSION INDIVIDUELLE */}
                        {(fileStatus.status === 'uploading' || fileStatus.status === 'success') && (
                          <div className="mt-2 bg-gray-200 dark:bg-gray-600 rounded-full h-2 overflow-hidden">
                            <div
                              className={`h-full transition-all duration-300 ${fileStatus.status === 'success'
                                ? 'bg-green-500'
                                : 'bg-gradient-to-r from-blue-500 to-purple-600'
                                }`}
                              style={{ width: `${fileStatus.progress}%` }}
                            >
                              {fileStatus.status === 'uploading' && (
                                <div className="h-full animate-pulse bg-white/20"></div>
                              )}
                            </div>
                          </div>
                        )}

                        {/* Message d'erreur */}
                        {fileStatus.status === 'error' && fileStatus.error && (
                          <p className="mt-1 text-xs text-red-500">
                            {fileStatus.error}
                          </p>
                        )}
                      </div>

                      {/* Bouton supprimer (seulement si pending ou error) */}
                      {!isUploading && (fileStatus.status === 'pending' || fileStatus.status === 'error') && (
                        <button
                          onClick={() => {
                            const index = fileStatuses.findIndex(f => f.id === fileStatus.id);
                            if (index !== -1) {
                              setFileStatuses((prev: FileUploadStatus[]) => prev.filter(f => f.id !== fileStatus.id));
                              setSelectedFiles((prevFiles: File[]) => prevFiles.filter((_: File, i: number) => i !== index));
                            }
                          }}
                          className="text-gray-400 hover:text-red-500 transition-colors p-2"
                        >
                          <i className="fas fa-times"></i>
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Étape 3 : Progression Globale */}
          {isUploading && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">3</span>
                Progression de l'upload
              </h3>

              {/* Barre de progression globale */}
              <div className="bg-gray-100 dark:bg-gray-700 rounded-full h-4 overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-purple-600 to-indigo-600 transition-all duration-300 flex items-center justify-end pr-2"
                  style={{ width: `${uploadProgress}%` }}
                >
                  <span className="text-xs text-white font-medium">
                    {Math.round(uploadProgress)}%
                  </span>
                </div>
              </div>

              {/* Statistiques */}
              <div className="mt-3 flex justify-between text-sm text-gray-600 dark:text-gray-400">
                <span>{successCount} réussi(s)</span>
                <span>{errorCount} erreur(s)</span>
                <span>{pendingCount} en attente</span>
              </div>
            </div>
          )}

          {/* Boutons d'action */}
          <div className="flex justify-end gap-3 pt-6 border-t border-gray-200 dark:border-gray-700">
            <button
              onClick={onClose}
              disabled={isUploading}
              className="px-6 py-3 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed text-gray-800 dark:text-gray-200 rounded-xl font-medium transition-all duration-200"
            >
              {isUploading ? 'Upload en cours...' : 'Annuler'}
            </button>
            <button
              onClick={handleUpload}
              disabled={selectedFiles.length === 0 || isUploading || !importType}
              className="px-6 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 disabled:from-gray-400 disabled:to-gray-500 text-white rounded-xl font-medium transition-all duration-200 flex items-center gap-2 disabled:cursor-not-allowed shadow-lg hover:shadow-xl"
            >
              {isUploading ? (
                <>
                  <i className="fas fa-spinner fa-spin"></i>
                  Import en cours... ({successCount}/{selectedFiles.length})
                </>
              ) : (
                <>
                  <i className="fas fa-upload"></i>
                  Importer {selectedFiles.length > 0 && `(${selectedFiles.length})`}
                </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ImportModal;
